80	function drawShape(ctx: CanvasRenderingContext2D, shape: Shape): void {
81	  ctx.save();
82	  ctx.fillStyle = shape.fill || "transparent";
83	  ctx.strokeStyle = shape.stroke || "#000000";
84	  ctx.lineWidth = shape.strokeWidth;
85	
86	  switch (shape.type) {
87	    case "rectangle":
88	      if (shape.fill) {
89	        ctx.fillRect(shape.x, shape.y, shape.width, shape.height);
90	      }
91	      ctx.strokeRect(shape.x, shape.y, shape.width, shape.height);
92	      break;
93	
94	    case "ellipse": {
95	      const cx = shape.x + shape.width / 2;
96	      const cy = shape.y + shape.height / 2;
97	      const rx = Math.abs(shape.width / 2);
98	      const ry = Math.abs(shape.height / 2);
99	      ctx.beginPath();
100	      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
101	      if (shape.fill) {
102	        ctx.fill();
103	      }
104	      ctx.stroke();
105	      break;
106	    }
107	
108	    case "line":
109	      ctx.beginPath();
110	      ctx.moveTo(shape.x, shape.y);
111	      ctx.lineTo(shape.x + shape.width, shape.y + shape.height);
112	      ctx.stroke();
113	      break;
114	
115	    case "text": {
116	      const fontSize = shape.fontSize || 16;
117	      ctx.font = `${fontSize}px sans-serif`;
118	      const measured = ctx.measureText(shape.text || "");
119	      // Update stored width to match actual rendered width for hit-testing
120	      shape.width = measured.width;
121	      shape.height = fontSize * 1.2; // line height
122	      ctx.fillStyle = shape.fill || "#000000";
123	      ctx.fillText(shape.text || "", shape.x, shape.y + fontSize);
124	      if (shape.stroke && shape.strokeWidth > 0) {
125	        ctx.strokeStyle = shape.stroke;
126	        ctx.lineWidth = shape.strokeWidth;
127	        ctx.strokeText(shape.text || "", shape.x, shape.y + fontSize);
128	      }
129	      break;
130	    }
131	  }
132	
133	  ctx.restore();
134	}
