136	function drawSelectionBox(ctx: CanvasRenderingContext2D, shape: Shape): void {
137	  ctx.save();
138	  ctx.strokeStyle = "#0088ff";
139	  ctx.lineWidth = 1;
140	  ctx.setLineDash([4, 4]);
141	  ctx.strokeRect(shape.x - 2, shape.y - 2, shape.width + 4, shape.height + 4);
142	  ctx.setLineDash([]);
143	
144	  // Draw handles at corners
145	  const handles = getHandlePositions(shape);
146	  ctx.fillStyle = "#0088ff";
147	  for (const h of handles) {
148	    ctx.fillRect(h.x, h.y, h.w, h.h);
149	  }
150	
151	  ctx.restore();
152	}
