154	export function getHandlePositions(
155	  shape: Shape
156	): { x: number; y: number; w: number; h: number; corner: string }[] {
157	  const hs = HANDLE_SIZE;
158	  const half = hs / 2;
159	  return [
160	    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
161	    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
162	    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
163	    {
164	      x: shape.x + shape.width - half + 2,
165	      y: shape.y + shape.height - half + 2,
166	      w: hs,
167	      h: hs,
168	      corner: "se",
169	    },
170	  ];
171	}
