173	function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
174	  ctx.save();
175	  ctx.globalAlpha = cursor.opacity ?? 1;
176	
177	  // Draw cursor arrow
178	  ctx.fillStyle = cursor.color;
179	  ctx.strokeStyle = "#ffffff";
180	  ctx.lineWidth = 1;
181	
182	  ctx.beginPath();
183	  ctx.moveTo(cursor.x, cursor.y);
184	  ctx.lineTo(cursor.x, cursor.y + 16);
185	  ctx.lineTo(cursor.x + 5, cursor.y + 12);
186	  ctx.lineTo(cursor.x + 10, cursor.y + 12);
187	  ctx.closePath();
188	  ctx.fill();
189	  ctx.stroke();
190	
191	  // Draw username label
192	  ctx.font = "11px sans-serif";
193	  const metrics = ctx.measureText(cursor.username);
194	  const labelX = cursor.x + 12;
195	  const labelY = cursor.y + 10;
196	  const padding = 3;
197	
198	  ctx.fillStyle = cursor.color;
199	  const rx = labelX - padding;
200	  const ry2 = labelY - 10 - padding;
201	  const rw = metrics.width + padding * 2;
202	  const rh = 14 + padding * 2;
203	  const r = 3;
204	  ctx.beginPath();
205	  ctx.moveTo(rx + r, ry2);
206	  ctx.lineTo(rx + rw - r, ry2);
207	  ctx.arcTo(rx + rw, ry2, rx + rw, ry2 + r, r);
208	  ctx.lineTo(rx + rw, ry2 + rh - r);
209	  ctx.arcTo(rx + rw, ry2 + rh, rx + rw - r, ry2 + rh, r);
210	  ctx.lineTo(rx + r, ry2 + rh);
211	  ctx.arcTo(rx, ry2 + rh, rx, ry2 + rh - r, r);
212	  ctx.lineTo(rx, ry2 + r);
213	  ctx.arcTo(rx, ry2, rx + r, ry2, r);
214	  ctx.closePath();
215	  ctx.fill();
216	
217	  ctx.fillStyle = "#ffffff";
218	  ctx.fillText(cursor.username, labelX, labelY);
219	
220	  ctx.restore();
221	}
