223	export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
224	  // Iterate in reverse z-order (topmost first)
225	  for (let i = shapes.length - 1; i >= 0; i--) {
226	    const s = shapes[i];
227	    if (isPointInShape(s, x, y)) {
228	      return s;
229	    }
230	  }
231	  return null;
232	}
233	
234	function isPointInShape(shape: Shape, px: number, py: number): boolean {
235	  const margin = 4;
236	  switch (shape.type) {
237	    case "rectangle":
238	    case "text":
239	      return (
240	        px >= shape.x - margin &&
241	        px <= shape.x + shape.width + margin &&
242	        py >= shape.y - margin &&
243	        py <= shape.y + shape.height + margin
244	      );
245	
246	    case "ellipse": {
247	      const cx = shape.x + shape.width / 2;
248	      const cy = shape.y + shape.height / 2;
249	      const rx = Math.abs(shape.width / 2) + margin;
250	      const ry = Math.abs(shape.height / 2) + margin;
251	      if (rx === 0 || ry === 0) return false;
252	      const dx = px - cx;
253	      const dy = py - cy;
254	      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
255	    }
256	
257	    case "line": {
258	      // Check distance from point to line segment
259	      const x1 = shape.x;
260	      const y1 = shape.y;
261	      const x2 = shape.x + shape.width;
262	      const y2 = shape.y + shape.height;
263	      const dist = distToSegment(px, py, x1, y1, x2, y2);
264	      return dist <= shape.strokeWidth / 2 + margin + 4;
265	    }
266	
267	    default:
268	      return false;
269	  }
270	}
271	
272	function distToSegment(
273	  px: number,
274	  py: number,
275	  x1: number,
276	  y1: number,
277	  x2: number,
278	  y2: number
279	): number {
280	  const dx = x2 - x1;
281	  const dy = y2 - y1;
282	  const lenSq = dx * dx + dy * dy;
283	  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
284	  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
285	  t = Math.max(0, Math.min(1, t));
286	  const projX = x1 + t * dx;
287	  const projY = y1 + t * dy;
288	  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
289	}
290	
291	export function hitTestHandle(
292	  shape: Shape,
293	  x: number,
294	  y: number
295	): string | null {
296	  const handles = getHandlePositions(shape);
297	  for (const h of handles) {
298	    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
299	      return h.corner;
300	    }
301	  }
302	  return null;
303	}
